// ── Data root discovery ────────────────────────────────────────────

struct DataDirs {
    std::string root;
    std::string data;
};

/// Find the root directory containing "CLASSIC Data/" and derive both
/// yaml_dir_root (the parent) and yaml_dir_data (the CLASSIC Data subdir).
/// Mirrors classic-gui/src/scan.rs: find_data_root() + load_analysis_config().
static DataDirs find_data_root() {
    std::error_code ec;
    fs::path exe_path = fs::current_path(ec); // fallback, overridden below

#ifdef _WIN32
    // Try getting actual exe path on Windows
    wchar_t buf[MAX_PATH];
    DWORD len = GetModuleFileNameW(nullptr, buf, MAX_PATH);
    if (len > 0 && len < MAX_PATH) {
        fs::path ep(buf);
        exe_path = ep.parent_path();
        if (fs::is_directory(exe_path / "CLASSIC Data", ec)) {
            return DataDirs{exe_path.string(), (exe_path / "CLASSIC Data").string()};
        }
    }
#endif

    // Check: Current working directory for "CLASSIC Data/" (development / distribution)
    auto cwd = fs::current_path(ec);
    if (fs::is_directory(cwd / "CLASSIC Data", ec)) {
        return DataDirs{cwd.string(), (cwd / "CLASSIC Data").string()};
    }

    // Check: Exe directory for "CLASSIC Data/" (running from build dir)
    if (fs::is_directory(exe_path / "CLASSIC Data", ec)) {
        return DataDirs{exe_path.string(), (exe_path / "CLASSIC Data").string()};
    }

    // Fallback: use cwd anyway (will fail at config load with a clear error)
    return DataDirs{cwd.string(), cwd.string()};
}

// ── Filename extraction helper ─────────────────────────────────────

static std::string filename_from_path(const std::string& path) {
    auto pos = path.find_last_of("/\\");
    return (pos != std::string::npos) ? path.substr(pos + 1) : path;
}

static std::string rust_string_to_std(const rust::String& value) {
    return std::string(value.data(), value.size());
}

static std::string startup_correlation_id() {
    char* env_value = nullptr;
    size_t env_len = 0;
    if (_dupenv_s(&env_value, &env_len, "CLASSIC_CORRELATION_ID") != 0 || env_value == nullptr) {
        return {};
    }

    std::string correlation_id(env_value);
    free(env_value);
    if (correlation_id.empty()) {
        return {};
    }
    return correlation_id;
}

class CliBatchProgressCallback final : public classic::scanner::ScanBatchProgressCallback {
public:
    explicit CliBatchProgressCallback(ProgressDisplay& progress)
        : progress_(progress) {}

    void on_batch_progress(const classic::scanner::BatchProgressEvent& event) const override {
        const std::string key = std::to_string(event.input_index);
        const std::string log_name = filename_from_path(rust_string_to_std(event.log_path));

        switch (event.event_kind) {
        case classic::scanner::BatchProgressEventKind::Started:
            progress_.report_started(key, log_name);
            break;
        case classic::scanner::BatchProgressEventKind::Completed:
            progress_.report_finished(key);
            break;
        case classic::scanner::BatchProgressEventKind::Failed:
            progress_.report_error(key);
            break;
        case classic::scanner::BatchProgressEventKind::Queued:
        case classic::scanner::BatchProgressEventKind::Phase:
            break;
        }
    }

private:
    ProgressDisplay& progress_;
};

// ── Scan pipeline (inner) ──────────────────────────────────────────
// Factored out so rust::Box<T> objects can be constructed in-place
// rather than pre-declared (rust::Box is non-nullable, no nullptr init).

static int run_scan_pipeline(const CliArgs& args, const DataDirs& dirs,
                             std::chrono::steady_clock::time_point total_start) {
    const auto prepared = prepare_scan_user_settings(args, dirs.root);
    if (!prepared.has_value()) {
        return 1;
    }

    classic::registry::registry_set_game(prepared->game);
    std::string mode_suffix;
    if (prepared->game_version != "auto") {
        mode_suffix += " " + prepared->game_version;
    }
    if (prepared->fcx_mode) {
        mode_suffix += " [FCX]";
    }
    fmt::print("CLASSIC v{} - Crash Log Scanner ({}{})\n\n", CLASSIC_CLI_VERSION, prepared->game, mode_suffix);

    // Discover crash logs -- targeted mode or standard discovery
    rust::Vec<rust::String> log_paths;
    const bool targeted_mode = !args.input_paths.empty();
    std::error_code ec;
    const std::string base_dir = fs::current_path(ec).string();
    const std::string custom_dir = prepared->custom_scan_directory;

    if (targeted_mode) {
        // Targeted mode: resolve explicit user-supplied paths
        rust::Vec<rust::String> rust_inputs;
        rust_inputs.reserve(args.input_paths.size());
        for (const auto& p : args.input_paths) {
            rust_inputs.push_back(rust::String(p));
        }
        auto resolution = classic::files::resolve_targeted_inputs(
            rust::Slice<const rust::String>(rust_inputs.data(), rust_inputs.size()));
        log_paths = std::move(resolution.logs);

        if (!resolution.rejected_paths.empty()) {
            auto n = resolution.rejected_paths.size();
            fmt::print("Rejected {} input{}:\n", n, n == 1 ? "" : "s");
            for (size_t i = 0; i < n; ++i) {
                fmt::print("  {} ({})\n",
                           std::string(resolution.rejected_paths[i].data(), resolution.rejected_paths[i].size()),
                           std::string(resolution.rejected_reasons[i].data(), resolution.rejected_reasons[i].size()));
            }
            fmt::print("\n");
        }
    } else {
        auto collector = classic::files::log_collector_new_for_scan(
            base_dir, dirs.data, prepared->game, prepared->game_version,
            prepared->configured_documents_root, custom_dir);
        log_paths = classic::files::log_collector_collect_all(*collector);

    }

    auto total_logs = static_cast<uint32_t>(log_paths.size());
    if (total_logs > 0) {
        fmt::print("Found {} crash log{}\n\n", total_logs, total_logs == 1 ? "" : "s");
    }

    // Scan all logs through the Rust Crash Log Scan Run seam.
    auto concurrency = effective_concurrency(prepared->max_concurrent, std::thread::hardware_concurrency());
    fmt::print("Scanning with {} concurrent scan{}\n\n", concurrency, concurrency == 1 ? "" : "s");

    ProgressDisplay progress(total_logs, prepared->game);
    CliBatchProgressCallback progress_callback(progress);
    auto cancellation_token = classic::scanner::scan_cancellation_token_new();

    std::atomic_bool render_running{true};
    std::thread render_thread([&progress, &render_running] {
        while (render_running.load(std::memory_order_relaxed)) {
            progress.render();
            std::this_thread::sleep_for(std::chrono::milliseconds(100));
        }
    });

    auto stop_renderer = [&] {
        render_running.store(false, std::memory_order_relaxed);
        if (render_thread.joinable()) {
            render_thread.join();
        }
    };

    auto scan_result = [&] {
        try {
            classic::scanner::ScanRunRequestDto request{};
            request.yaml_dir_root = rust::String(dirs.root);
            request.yaml_dir_data = rust::String(dirs.data);
            request.game = rust::String(prepared->game);
            request.game_version = rust::String(prepared->game_version);
            request.base_directory = rust::String(base_dir);
            request.custom_scan_directory = rust::String(custom_dir);
            request.configured_documents_root = rust::String(prepared->configured_documents_root);
            request.show_formid_values = prepared->show_formid_values;
            for (const auto& path : prepared->formid_database_paths) {
                request.formid_database_paths.push_back(rust::String(path));
            }
            request.fcx_mode = prepared->fcx_mode;
            request.simplify_logs = prepared->simplify_logs;
            request.move_unsolved_logs = prepared->move_unsolved_logs;
            request.unsolved_logs_destination = rust::String(prepared->unsolved_logs_destination);
            request.targeted_mode = targeted_mode;
            request.setup_game_root = rust::String(prepared->setup_game_root);
            request.setup_docs_root = rust::String(prepared->setup_docs_root);
            request.setup_game_exe_path = rust::String(prepared->setup_game_exe_path);
            request.setup_xse_log_path = rust::String(prepared->setup_xse_log_path);
            request.max_concurrent = concurrency;
            for (const auto& input : args.input_paths) {
                request.targeted_inputs.push_back(rust::String(input));
            }
            request.log_paths = std::move(log_paths);
            return classic::scanner::scan_run_execute(request, progress_callback, *cancellation_token);
        } catch (...) {
            stop_renderer();
            progress.finish();
            throw;
        }
    }();
    const auto& results = scan_result.logs;

    stop_renderer();
    progress.render();
    progress.finish();

    const std::string run_status(scan_result.status.data(), scan_result.status.size());
    if (run_status == "no_crash_logs_found") {
        const std::string message = scan_result.message.empty()
                                        ? (custom_dir.empty() ? fmt::format("No crash logs found in: {}", base_dir)
                                                              : fmt::format("No crash logs found in: {} or {}", base_dir, custom_dir))
                                        : std::string(scan_result.message.data(), scan_result.message.size());
        fmt::print("{}\n", message);
        return 0;
    }
    if (run_status == "setup_failed") {
        const std::string message = scan_result.message.empty()
                                        ? "Crash Log Scan setup failed"
                                        : std::string(scan_result.message.data(), scan_result.message.size());
        fmt::print(stderr, "{}\n", message);
        return 1;
    }

    uint32_t reports_written = 0;
    uint32_t error_count = 0;
    uint32_t moved_to_unsolved_logs = 0;

    for (const auto& result : results) {
        if (result.success && !result.autoscan_report_path.empty()) {
            ++reports_written;
        }
        if (!result.success) {
            ++error_count;
        }
        if (result.moved_to_unsolved_logs) {
            ++moved_to_unsolved_logs;
        }
    }

    // D-11 / CXXS-03 consumer migration (Codex HIGH correction):
    // After the scan completes, surface any FCX configuration issues that the
    // analysis pipeline detected. This call exercises the new bridge fn from
    // every CLI scan run, satisfying ROADMAP.md Phase 2 success criterion 2.
    try {
        auto fcx_issues = classic::scanner::get_fcx_config_issues();
        if (!fcx_issues.empty()) {
            fmt::print("\nFCX Configuration Issues Detected ({}):\n", fcx_issues.size());
            for (const auto& issue : fcx_issues) {
                std::string file_path(issue.file_path.data(), issue.file_path.size());
                std::string setting(issue.setting.data(), issue.setting.size());
                std::string current(issue.current_value.data(), issue.current_value.size());
                std::string recommended(issue.recommended_value.data(), issue.recommended_value.size());
                std::string description(issue.description.data(), issue.description.size());
                std::string severity(issue.severity.data(), issue.severity.size());
                if (issue.has_section) {
                    std::string section(issue.section_or_empty.data(), issue.section_or_empty.size());
                    fmt::print("  [{}] {}/[{}] {}: {} (current: {}, recommended: {})\n", severity, file_path, section,
                               setting, description, current, recommended);
                } else {
                    fmt::print("  [{}] {} {}: {} (current: {}, recommended: {})\n", severity, file_path, setting,
                               description, current, recommended);
                }
            }
        }
    } catch (const rust::Error& e) {
        // Fail-soft: FCX surface is non-critical for the CLI exit code
        fmt::print(stderr, "Warning: failed to read FCX issues: {}\n", std::string(e.what()));
    }

    // Print summary
    auto total_end = std::chrono::steady_clock::now();
    double duration = std::chrono::duration<double>(total_end - total_start).count();
    total_logs = scan_result.total;
    double speed = (duration > 0.0) ? (total_logs / duration) : 0.0;

    fmt::print("\nScan Complete\n");
    fmt::print("  Scanned:  {} log{}\n", total_logs, total_logs == 1 ? "" : "s");
    if (error_count > 0) {
        fmt::print("  Errors:   {} log{}\n", error_count, error_count == 1 ? "" : "s");
    }
    fmt::print("  Reports:  {} written\n", reports_written);
    if (moved_to_unsolved_logs > 0) {
        fmt::print("  Unsolved: {} moved\n", moved_to_unsolved_logs);
    }
    fmt::print("  Duration: {:.2f}s\n", duration);
    fmt::print("  Speed:    {:.1f} logs/sec\n", speed);

    return (error_count > 0) ? 1 : 0;
}

// ── Public entry point ─────────────────────────────────────────────

int run_scan(const CliArgs& args) {
    auto total_start = std::chrono::steady_clock::now();
    const std::string correlation_id = startup_correlation_id();

    // Initialize Rust runtime + logging
    try {
        classic::message::init_logging();
        classic::runtime::init_runtime();
        classic::message::log_startup_binding_contract_validated("classic-cli.startup", 3, correlation_id);
        classic::message::log_startup_acceleration_status(1, 1, "MANDATORY", correlation_id);
    } catch (const rust::Error& e) {
        classic::message::log_startup_binding_contract_failed(
            "classic-cli.startup", "classic::runtime::init_runtime", "runtime_init",
            "Run classic-cli/build_cli.ps1 to rebuild the C++ bridge and verify runtime dependencies.", e.what(),
            correlation_id);
        fmt::print(stderr, "Fatal: failed to initialize runtime: {}\n", std::string(e.what()));
        return 2;
    }

    // Find data root
    auto dirs = find_data_root();
    fmt::print("Data root: {}\n", dirs.root);
    fmt::print("Data dir:  {}\n\n", dirs.data);

    // Run the scan pipeline (all rust::Box<T> objects live inside this scope)
    int exit_code;
    try {
        exit_code = run_scan_pipeline(args, dirs, total_start);
    } catch (const rust::Error& e) {
        fmt::print(stderr, "Fatal: {}\n", std::string(e.what()));
        exit_code = 2;
    }

    classic::runtime::shutdown_runtime();
    return exit_code;
}
